const raw = $input.first().json;
const body = raw && (typeof raw.body !== 'undefined' ? raw.body : raw) || {};
const cancelledBy = String(body.cancelled_by || '').toLowerCase();
const isBarber = cancelledBy === 'barber';
return [{ json: { body, isBarber } }];

const raw = $input.first().json;
const body = raw.body || raw;
const phone = (body.client_phone || body.phone || '').replace(/\D/g, '');
const number = phone.length === 11 ? '55' + phone : phone;
const clientName = body.client_name || body.clientName || 'Cliente';
const barberName = body.barber_name || body.barberName || 'Barbeiro';
const serviceName = body.service_name || body.serviceName || 'Serviço';
const date = body.appointment_date || body.date || '';
const time = body.appointment_time || body.time || '';
let dateFormatted = (date && typeof date === 'string') ? String(date).trim() : '';
if (dateFormatted.length >= 10 && dateFormatted.includes('-')) {
  const parts = dateFormatted.slice(0, 10).split('-');
  if (parts.length === 3 && parts[0] && parts[1] && parts[2]) dateFormatted = `${parts[2]}/${parts[1]}/${parts[0]}`;
}
const timeFormatted = (time || '').toString().slice(0, 5);
const message = `❌ *Cancelamento pelo estabelecimento*\n\nOlá, ${clientName}!\n\nInfelizmente precisamos cancelar seu agendamento.\n📅 Data: ${dateFormatted}\n🕐 Horário: ${timeFormatted}\n✂️ Serviço: ${serviceName}\n👤 Barbeiro: ${barberName}\n\nPedimos desculpas pelo inconveniente. Agende um novo horário quando quiser!`;
return [{ json: { number, message } }];

